(1, 'Detective Mystery', 'detective-mystery', '<p><span data-metadata=\"&lt;!--(figmeta)eyJmaWxlS2V5IjoiZU1ZNnpzSHZwdjFuanR0WEVnYzk2ciIsInBhc3RlSUQiOjE5ODQ4NjQwOTIsImRhdGFUeXBlIjoic2NlbmUiLCJlbnZpcm9ubWVudCI6Ind3dy5maWdtYS5jb20iLCJzZWxlY3RlZE5vZGVEYXRhIjoiMzM4OTo5Mjh8MzF8MCJ9Cg==(/figmeta)--&gt;\"></span><span data-buffer=\"&lt;!--(figma)(/figma)--&gt;\"></span><span style=\"white-space: pre-wrap;\">A story-driven team challenge where employees collaborate, question, and compete to solve the case.\r\n</span></p><ul role=\"list\"><li style=\"white-space: pre-wrap;\">Role-based activity (Investigator, Culprit, Witness, and more)</li><li style=\"white-space: pre-wrap;\"> Real-time questioning and deduction Tetst</li><li style=\"white-space: pre-wrap;\"> Time-bound challenges to maintain urgency</li><li style=\"white-space: pre-wrap;\"> Built for communication and strategic thinking</li></ul><p><span style=\"white-space: pre-wrap;\"></span></p><p><span style=\"white-space: pre-wrap;\">Builds stronger communication, sharper thinking, and real team collaboration in a high-energy environment.</span></p>', 'activities/TEOZeXmAJdCAs1KKU5r9c2hiXPctabJCo0X0yLea.jpg', 'activities/icons/kS2vRdgOZo4Yc8uD87fYHXb1TU7dFdrY8bSVKz4s.png', 'active', 900, 15, 1500, 300, 120, 600, 120, 5, 5, 5, 100, 50, 20, -10, -15, 1, 3, 420, 30, '2026-05-26 12:29:06', '2026-07-06 16:12:19');
