INSERT INTO `activity_games` (`id`, `activity_id`, `title`, `case_summary`, `timeline`, `quick_facts`, `tagline`, `status`, `created_at`, `updated_at`, `victim_name`) VALUES
(1, 1, 'The Bungalow Secret', '<h3>Case Plot</h3><p>An old wealthy businessman, Raghav Malhotra, is found dead in his luxury bungalow on the night of his greatest triumph — the approval celebration for his ambitious Dream City Project.</p><p>The project, a large-scale real estate development, was built on land acquired from local farming communities under disputed and allegedly forced conditions.</p><p>The party was in full swing. Guests, business associates, and family were present. But behind the celebrations, tensions ran deep.</p><p>Medical estimation places time of death at approximately 11:30 PM.</p><p>Businessman was found dead in the room.</p>', '[{\"time\": \"10:00 PM\", \"event\": \"Party AAAAA begins at the Bungalow — guests, associates, media arrive\"}, {\"time\": \"10:30 PM\", \"event\": \"Raghav B Malhotra gives victory speech celebrating Dream City Project approval\"}, {\"time\": \"10:45 PM\", \"event\": \"Guest C dancing and enjoying with loud music, dinner\"}, {\"time\": \"11:00 PM\", \"event\": \"Farmer’s leader Kartar Sah arrives uninvited and starts shouting in party\"}, {\"time\": \"11:10 PM\", \"event\": \"Raghav D Malhotra asks him to come to his private room to discuss peacefully\"}, {\"time\": \"11:20 PM\", \"event\": \"Raghav calls his son Vikram — call lasts 4 minutes (last call on his phone)\"}, {\"time\": \"11:30 PM\", \"event\": \"Kartar Sah exits study, leaves bungalow — confirmed by gate guard.\"}, {\"time\": \"11:50 PM\", \"event\": \"Raju enters with tea — finds dead body. Raju informs police.\"}]', '{\"weather\": \"Clear Night\", \"location\": \"Luxury Bungalow, Mumbai\", \"date_time\": \"26th May, 11:30 PM (Est. Death)\", \"cctv_status\": \"Operational (Limited Coverage)\"}', 'Not everything is as it seems in the Willow Bungalow.', 'active', '2026-05-26 12:29:06', '2026-07-07 17:22:00', 'Raghav Malhotra'),
(5, 1, 'The File Holl Secret', '<h3>Case Plot</h3><p>An old wealthy businessman, Raghav Malhotra, is found dead in his luxury bungalow on the night of his greatest triumph — the approval celebration for his ambitious Dream City Project.</p><p>The project, a large-scale real estate development, was built on land acquired from local farming communities under disputed and allegedly forced conditions.</p><p>The party was in full swing. Guests, business associates, and family were present. But behind the celebrations, tensions ran deep.</p><p>Medical estimation places time of death at approximately 11:30 PM.</p><p>Businessman was found dead in the room.</p>', '[{\"time\": \"10:00 PM\", \"event\": \"Party begins at the Bungalow — guests, associates, media arrive\"}, {\"time\": \"10:30 PM\", \"event\": \"Raghav Malhotra gives victory speech celebrating Dream City Project approval\"}, {\"time\": \"10:45 PM\", \"event\": \"Guest dancing and enjoying with loud music, dinner\"}, {\"time\": \"11:00 PM\", \"event\": \"Farmer’s leader Kartar Sah arrives uninvited and starts shouting in party\"}, {\"time\": \"11:10 PM\", \"event\": \"Raghav Malhotra asks him to come to his private room to discuss peacefully\"}, {\"time\": \"11:20 PM\", \"event\": \"Raghav calls his son Vikram — call lasts 4 minutes (last call on his phone)\"}, {\"time\": \"11:30 PM\", \"event\": \"Kartar Sah exits study, leaves bungalow — confirmed by gate guard.\"}, {\"time\": \"11:50 PM\", \"event\": \"Raju enters with tea — finds dead body. Raju informs police.\"}]', '{\"weather\": \"Clear Night\", \"location\": \"Luxury Bungalow, Mumbai\", \"date_time\": \"26th May, 11:30 PM (Est. Death)\", \"cctv_status\": \"Operational (Limited Coverage)\"}', 'Not everything is as it seems in the Willow Bungalow.', 'active', '2026-06-05 15:35:05', '2026-06-05 15:35:29', NULL),
(6, 1, 'The College Hostel', '<h3>Case Plot</h3><p>An old wealthy businessman, Raghav Malhotra, is found dead in his luxury bungalow on the night of his greatest triumph — the approval celebration for his ambitious Dream City Project.</p><p>The project, a large-scale real estate development, was built on land acquired from local farming communities under disputed and allegedly forced conditions.</p><p>The party was in full swing. Guests, business associates, and family were present. But behind the celebrations, tensions ran deep.</p><p>Medical estimation places time of death at approximately 11:30 PM.</p><p>Businessman was found dead in the room.</p>', '[{\"time\": \"10:00 PM\", \"event\": \"Party begins at the Bungalow — guests, associates, media arrive\"}, {\"time\": \"10:30 PM\", \"event\": \"Raghav Malhotra gives victory speech celebrating Dream City Project approval\"}, {\"time\": \"10:45 PM\", \"event\": \"Guest dancing and enjoying with loud music, dinner\"}, {\"time\": \"11:00 PM\", \"event\": \"Farmer’s leader Kartar Sah arrives uninvited and starts shouting in party\"}, {\"time\": \"11:10 PM\", \"event\": \"Raghav Malhotra asks him to come to his private room to discuss peacefully\"}, {\"time\": \"11:20 PM\", \"event\": \"Raghav calls his son Vikram — call lasts 4 minutes (last call on his phone)\"}, {\"time\": \"11:30 PM\", \"event\": \"Kartar Sah exits study, leaves bungalow — confirmed by gate guard.\"}, {\"time\": \"11:50 PM\", \"event\": \"Raju enters with tea — finds dead body. Raju informs police.\"}]', '{\"weather\": \"Clear Night\", \"location\": \"Luxury Bungalow, Mumbai\", \"date_time\": \"26th May, 11:30 PM (Est. Death)\", \"cctv_status\": \"Operational (Limited Coverage)\"}', 'Not everything is as it seems in the Willow Bungalow.', 'active', '2026-06-05 15:35:40', '2026-06-05 15:36:31', NULL),
(7, 1, 'The School Scame', '<h3>Case Plot</h3><p>An old wealthy businessman, Raghav Malhotra, is found dead in his luxury bungalow on the night of his greatest triumph — the approval celebration for his ambitious Dream City Project.</p><p>The project, a large-scale real estate development, was built on land acquired from local farming communities under disputed and allegedly forced conditions.</p><p>The party was in full swing. Guests, business associates, and family were present. But behind the celebrations, tensions ran deep.</p><p>Medical estimation places time of death at approximately 11:30 PM.</p><p>Businessman was found dead in the room.</p>', '[{\"time\": \"10:00 PM\", \"event\": \"Party begins at the Bungalow — guests, associates, media arrive\"}, {\"time\": \"10:30 PM\", \"event\": \"Raghav Malhotra gives victory speech celebrating Dream City Project approval\"}, {\"time\": \"10:45 PM\", \"event\": \"Guest dancing and enjoying with loud music, dinner\"}, {\"time\": \"11:00 PM\", \"event\": \"Farmer’s leader Kartar Sah arrives uninvited and starts shouting in party\"}, {\"time\": \"11:10 PM\", \"event\": \"Raghav Malhotra asks him to come to his private room to discuss peacefully\"}, {\"time\": \"11:20 PM\", \"event\": \"Raghav calls his son Vikram — call lasts 4 minutes (last call on his phone)\"}, {\"time\": \"11:30 PM\", \"event\": \"Kartar Sah exits study, leaves bungalow — confirmed by gate guard.\"}, {\"time\": \"11:50 PM\", \"event\": \"Raju enters with tea — finds dead body. Raju informs police.\"}]', '{\"weather\": \"Clear Night\", \"location\": \"Luxury Bungalow, Mumbai\", \"date_time\": \"26th May, 11:30 PM (Est. Death)\", \"cctv_status\": \"Operational (Limited Coverage)\"}', 'Not everything is as it seems in the Willow Bungalow.', 'active', '2026-06-05 15:35:55', '2026-06-11 15:28:36', NULL);

