INSERT INTO `game_roles` (`id`, `game_id`, `role_type`, `character_name`, `subtitle`, `role_image`, `objective`, `what_you_know`, `keep_in_mind`, `footer_text`, `created_at`, `updated_at`) VALUES
(1, 1, 'investigator', 'Investigator', 'You are the Investigator. The only one allowed to question everyone.', 'roles/ghRgXwLTsQLgVU4ktAza2dSL4jRk2F0WG8bgnofu.jpg', 'Find and accuse the real Hidden Culprit before time runs out.', '[\"Everyone in the house is a suspect\", \"Statements may not be truthful\", \"The timeline holds key inconsistencies\"]', '[\"You can ask up to 5 questions in total\", \"You can use the Lie Detector round for up to 7 minutes\", \"You can reopen the Case Brief only once when the session starts\", \"You win if you correctly identifies the Hidden Culprit\", \"+10 points per question asked\"]', 'Keep your role secret. CTA button: Okay, continue', '2026-05-26 12:29:06', '2026-06-05 15:33:47'),
(2, 1, 'culprit', 'Priya Malhotra (Daughter-in-law)', 'You are the one who did it. Stay calm. Stay hidden.', 'roles/dbVZUBixI8004ZjOnkNtrFgWlMNqUcNY1UbxFUwC.jpg', 'Avoid getting caught by the Investigator and ensure someone else is identified as the accused.', '[\"Your alibi has been assigned — stick to it\", \"A Person of Interest has been named in the case — use them\", \"The Investigator has only 5 questions — make them count for nothing\"]', '[\"Act like a normal participant — not too silent, not too defensive\", \"Slightly redirect facts instead of outright lying\", \"Casually raise doubts about the Person of Interest in your answers\", \"Stick to one story throughout the entire session\", \"You win if you are not identified.\", \"Your role is confidential. Do not reveal it directly or indirectly.\"]', 'Keep your role secret. CTA button: Okay, continue', '2026-05-26 12:29:06', '2026-06-05 15:33:47'),
(3, 1, 'suspect', 'Kartar Sah (Farmer Leader)', 'You are under suspicion. Prove you are innocent.', 'roles/7Nn83ZzLJg9v3fPg2GwcTaJGfNUTjroRB1bsABzg.jpg', 'Avoid being wrongly identified as the accused by the Investigator.', '[\"Your presence or connection to the incident raises doubt\", \"The case may reference details that appear to implicate you\", \"You are innocent — but you must prove it through your answers\"]', '[\"Stay calm and composed under questioning\", \"Give clear, consistent answers — do not change your story\", \"Do not panic or over-explain when challenged\", \"You win if you correctly identifies the Hidden Culprit\", \"Your role is confidential. Do not reveal it directly or indirectly.\"]', 'Keep your role secret. CTA button: Okay, continue', '2026-05-26 12:29:06', '2026-06-05 15:33:47'),
(4, 1, 'witness', 'Raju (Servant)', 'You saw something. Help the Investigator — carefully.', 'roles/ee79TN7Q3eWbaK7Xlu2CaznkiKzo0tQmjAwhb93a.jpg', 'Help the Investigator identify the Hidden Culprit without revealing everything too easily.', '[\"You have partial knowledge of the incident\", \"You may have noticed suspicious behaviour or movements\", \"You hold one Secret Passcard — a private hint to the Investigator\"]', '[\"Share information gradually — do not give everything away at once\", \"Be truthful but controlled in your responses\", \"Use your Secret Passcard wisely\", \"You win if you correctly identifies the Hidden Culprit\", \"Your role is confidential. Do not reveal it directly or indirectly.\"]', 'Keep your role secret. CTA button: Okay, continue', '2026-05-26 12:29:06', '2026-06-07 18:26:12'),
(5, 1, 'participant', 'Vikram Malhotra (Son)', 'You are a neutral observer. Stay active and think clearly.', 'roles/BEspNHn7GRn7WN8i2qK0U5oOxFZXnmsU6XWJzUly.jpg', 'Help ensure the correct accused is identified by actively participating.', '[\"You have no hidden agenda\", \"You are not under special suspicion\", \"Your observations and logical reasoning are your only tools\"]', '[\"Stay active — do not go silent\", \"Answer questions honestly and consistently\", \"Observe others carefully for inconsistencies\", \"You win if you correctly identifies the Hidden Culprit\", \"Your role is confidential. Do not reveal it directly or indirectly.\"]', 'Keep your role secret. CTA button: Okay, continue', '2026-05-26 12:29:06', '2026-06-05 15:33:47'),
