CREATE TABLE `investigator_cards` (
  `id` bigint UNSIGNED NOT NULL,
  `game_id` bigint UNSIGNED NOT NULL,
  `card_number` tinyint UNSIGNED NOT NULL,
  `suspect_label` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `tag` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `profile_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `why_suspicious` json DEFAULT NULL,
