INSERT INTO `investigator_cards` (`id`, `game_id`, `card_number`, `suspect_label`, `tag`, `profile_text`, `why_suspicious`, `suggested_questions`, `appears_at_secs`, `closes_at_secs`, `created_at`, `updated_at`) VALUES
(53, 5, 1, 'Suspect 1: Kartar Sah', 'Farmer Leader — Uninvited Guest', 'Kartar Sah was the last known person inside the study with Raghav Malhotra. He left at exactly 11:30 PM — the estimated time of death. He had the loudest, most public motive — two years of protests, legal battles, and public threats against Raghav. Land registry papers with his name were found scattered across the study floor.', NULL, NULL, 5, 35, '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(54, 5, 2, 'Suspect 2: Vikram Malhotra', 'The Heir', 'Vikram Malhotra is the only son of Raghav Malhotra and the sole heir. At 11:20 PM — 10 minutes before the death — Raghav called Vikram. The call lasted 4 minutes. It was the last call ever made from Raghav\'s phone.', NULL, NULL, 155, 185, '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(55, 5, 3, 'Suspect 3: Raju', 'The Servant', 'Raju has worked in the bungalow for 11 years. He knows every private corridor. Kitchen log shows the kettle was boiled at 11:20 PM — unusually early. He is the only staff member who knew Kartar Sah personally.', NULL, NULL, 305, 335, '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(56, 5, 4, 'Suspect 4: Priya Malhotra', 'The Daughter-in-law', 'Priya Malhotra claims she was socialising near the dining area. However, no guest can confirm her exact location between 11:25 PM and 11:45 PM. She was seen near the kitchen at 11:15 PM.', NULL, NULL, 455, 485, '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
