INSERT INTO `strategy_cards` (`id`, `role_id`, `card_number`, `heading`, `heading_color`, `body_content`, `created_at`, `updated_at`) VALUES
(209, 22, 1, 'Your Role', '#7f77dd', 'You did it. You know it. Nobody else does yet. Your only job tonight is to walk out of this without being named.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(210, 22, 2, 'Your Alibi', '#7f77dd', 'You were socialising near the dining area between 11:15 PM and 11:45 PM. You stepped away briefly to wash face. Stick to one version.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(211, 22, 3, 'Person of Interest', '#7f77dd', 'Kartar Sah was in the room at the time of death and he was shouting in party. That is a fact available to everyone.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(212, 22, 4, 'Stay In The Game', '#7f77dd', 'Act normal — grief is natural tonight. Less is more — short answers are safer. One story — never contradict yourself.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(213, 23, 1, 'Your Situation', '#7f77dd', 'All eyes are on you. But you didn\'t do it. Objective: Survive the investigation. You arrived uninvited. You were alone with Raghav. You left at exactly the time they say he died.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(214, 23, 2, 'What You Actually Know', '#7f77dd', 'Facts: You came to confront Raghav about the land issue. Discussion was heated but you left him alive. You walked out at 11:30 PM. The gate guard saw you leave.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(215, 23, 3, 'Your Weak Points', '#7f77dd', 'Land papers with your name found at the scene. Your history of public threats. Don\'t panic.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(216, 23, 4, 'How To Stay Alive', '#7f77dd', 'Anger is natural — own it but separate it from violence. Stay calm. Tell your truth.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(217, 24, 1, 'Your Situation', '#7f77dd', 'You have worked here 11 years. You found the body. You did nothing wrong. But you knew Kartar Sah personally. The Investigator will notice.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(218, 24, 2, 'What You Actually Know', '#7f77dd', 'Facts: You were in the kitchen from 11:20 PM. You entered study at 11:50 PM. You know Kartar from home district. You boiled kettle early for a simple reason — pick one and stick to it.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(219, 24, 3, 'Your Weak Points', '#7f77dd', 'Why was the kettle boiled 30 minutes early? Your personal connection to Kartar Sah.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(220, 24, 4, 'How To Handle The Investigation', '#7f77dd', 'You are not a suspect. Kartar connection — a shared district is not a crime. You have nothing to hide except one small habit.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(221, 25, 1, 'Your Situation', '#7f77dd', 'Your father called you at 11:20 PM. Last call. You walked toward study after. Staff saw you near east corridor at 11:26 PM. You turned back without entering.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(222, 25, 2, 'What You Actually Know', '#7f77dd', 'Facts: Father called at 11:20 PM (4 mins). He was planning to transfer 95% of estate to farmer trust. You were shocked and walked toward study. You heard voices and turned back.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(223, 25, 3, 'Your Weak Points', '#7f77dd', 'What father said in those 4 mins. Why you walked toward study. Why you turned back. Where you were between 11:24 and 11:40 PM.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
(224, 25, 4, 'How To Handle The Investigation', '#7f77dd', 'You are grieving — it\'s real. Own your corridor movement. Phone call content — you decide if you want to share.', '2026-06-05 15:35:29', '2026-06-05 15:35:29'),
